INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-7ec62a85-moex-00252', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '甲建管機關核發乙公司建照後，於乙施工期間，鄰人丙偶然發現該建照恐有違法瑕疵，下列敘述何者 正確？', '["丙向甲舉發違法後，甲應訴請法院撤銷該違法行政處分，但應考量乙之信賴利益", "甲應先命乙暫停施工，並靜待檢調機關調查有無違法後，始得依職權撤銷該建照", "於法定救濟期間經過後，丙仍得以利害關係人之身分，向甲申請撤銷該違法建照", "丙應先向行政法院申請假扣押乙之施工機具，以防甲藉由儘早完工試圖規避違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00253', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者屬於已發生效力之行政處分？', '["對特定違規業者作成停止其營業之命令", "已經執行完畢之違章建築強制拆除行為", "應人民請求而公開之空氣污染調查報告", "未公告或刊登政府公報之書面一般處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00254', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何種情形，不適用公法上不當得利返還請求權？', '["甲公務員因溢領一次性退休金之給付，主管機關撤銷原核定處分後，命甲返還溢領金額", "乙繳付工業區開發管理基金後，因非可歸責於己之事由而未設廠，向主管機關請求返還", "丙之土地經徵收並領取補償金後，經查計算標準錯誤有溢領情形，補償機關請求丙返還", "丁廠商參與政府採購得標並已完工驗收，主管機關未給付工程尾款，丁訴請該機關返還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00255', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政機關與人民締結互負給付義務之行政契約，下列敘述何者錯誤？', '["契約中應約定人民給付之目的", "契約之締結應以書面為之", "人民之給付與行政機關之給付未相當者，該契約無效", "人民之給付不限於行政機關之特定用途"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00256', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '需用土地人申請徵收土地前，與土地所有人達成之協議價購，其法律性質為何？', '["行政契約", "行政處分", "私法契約", "事實行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00257', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依最高行政法院實務見解，下列何者非屬觀念通知？', '["主管機關同意甫成立之公寓大廈管理委員會依法所為之報備", "公平交易委員會對檢舉人所為檢舉不成立之函文", "主管機關通知人民自行拆除違章建築之違章建築拆除通知單", "主管機關對人民團體選任職員簡歷冊之異動所為之核備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00258', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依據行政罰法與學理之見解，關於行政罰之敘述，下列何者正確？', '["為避免行政機關執法困擾，行政罰法得類推適用刑法共犯制度之規定", "個別法規有推定過失特別規定時，應優先於行政罰法責任條件之規定", "對同一違反義務行為，禁止同時科處行政罰並作成單純不利益行政處分", "對違反行政法上義務之行為，地方行政機關僅得依地方議會制定自治條例處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00259', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依最高行政法院裁判見解，關於行政罰法中法律變更時之適用原則之敘述，下列何者錯誤？', '["行政罰法規定行為後法律有變更者，適用行政機關最初裁處時之法律，為從新原則之具體化", "行為後法律雖有變更，如裁處前之法律係有利於受處罰者，適用最有利於受處罰者之規定", "行政機關依法律授權所為之公告，因會對外發生規範效力，故其內容之變更亦屬法律變更", "行政機關為行使裁量權所訂頒之裁量基準，因非屬法律，故其變更即非屬法律變更之情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00260', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '甲向主管機關申領身心障礙給付後，檢察官以詐欺取財罪對甲作成緩起訴處分。主管機關乃依法就其 詐領給付之行為，處以給付額兩倍之罰鍰。其裁處權時效應如何起算？', '["自主管機關知悉甲違法時起算", "自甲持不實資料向主管機關提出申請時起算", "自甲受領身心障礙給付時起算", "自檢察官緩起訴處分確定時起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00261', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-110-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者屬於行政罰法之規制範圍？', '["證券交易法第 59 條第 1 項規定：「證券商自受領證券業務特許證照，或其分支機構經許可並登記 後，於三個月內未開始營業，或雖已開業而自行停止營業連續三個月以上時，主管機關得撤銷其特 許或許可。」", "稅捐稽徵法第24條第1項前段規定：「納稅義務人欠繳應納稅捐者，稅捐稽徵機關得就納稅義務人 相當於應繳稅捐數額之財產，通知有關機關，不得為移轉或設定他項權利。」", "所得稅法第43條之2第1項規定：「自一百年度起，營利事業對關係人之負債占業主權益超過一定 比率者，超過部分之利息支出不得列為費用或損失。」", "道路交通管理處罰條例第12條第1項規定：「汽車有下列情形之一者，處汽車所有人新臺幣三千六 百元以上一萬零八百元以下罰鍰，......。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "417", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL)
